using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // --- Services ---

        // Singleton: one HttpClient and one DataService for the entire app.
        // The REST-API service holds an HttpClient and possibly auth tokens /
        // a cache, so sharing a single instance avoids socket exhaustion and
        // keeps cached data consistent across all consumers.
        builder.Services.AddSingleton<HttpClient>();
        builder.Services.AddSingleton<IDataService, DataService>();

        // --- ViewModels ---

        // Transient: a fresh ViewModel every time a page is created.
        // This guarantees each page navigation starts with clean state
        // (no stale data left over from a previous visit) and avoids
        // accidental shared-state bugs between pages.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // --- Pages ---

        // Transient: a new page instance per navigation.
        // MAUI's Shell/NavigationPage pushes new page objects onto the
        // nav stack, so transient is the natural fit.  It also pairs
        // with the transient ViewModels above — each page gets its own VM.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

